package distlock_test

import (
	"context"
	"fmt"
	"testing"
	"time"

	"github.com/ghbvf/gocell/kernel/clock/clockmock"
	"github.com/ghbvf/gocell/runtime/distlock/locktest"
)

// TestRandomToken_LengthAndUniqueness verifies that the token generated by
// randomToken() is:
//   - 64 hex characters long (32 bytes × 2)
//   - Unique across 1000 acquisitions
//
// randomToken() is unexported; we observe tokens through FakeDriver.Snapshot()
// after each Acquire().
func TestRandomToken_LengthAndUniqueness(t *testing.T) {
	const n = 1000

	fc := clockmock.New(time.Time{})
	fd := locktest.NewFakeDriver()
	l := mustNewLocker(fd, fc)

	tokens := make(map[string]bool, n)
	releases := make([]func() error, 0, n)

	for i := range n {
		key := fmt.Sprintf("token-test-key-%d", i)
		_, release, err := l.Acquire(context.Background(), key, time.Minute)
		if err != nil {
			t.Fatalf("Acquire[%d]: %v", i, err)
		}
		releases = append(releases, release)

		// Snapshot to get the token stored in the driver.
		snap := fd.Snapshot()
		tok, ok := snap[key]
		if !ok {
			t.Fatalf("key %q not found in snapshot after Acquire[%d]", key, i)
		}

		// Length: 64 hex chars (32 bytes × 2).
		if len(tok) != 64 {
			t.Errorf("token[%d] length = %d, want 64", i, len(tok))
		}

		// Uniqueness.
		if tokens[tok] {
			t.Errorf("duplicate token detected at iteration %d: %q", i, tok)
		}
		tokens[tok] = true
	}

	// Clean up.
	for _, release := range releases {
		if err := release(); err != nil {
			t.Logf("release: %v", err)
		}
	}
}
